import itertools, math, random, numpy as np
def prob_success(weights,p):
    m=len(weights)
    res=0.0
    for mask in range(1<<m):
        s=0; k=0
        for i,w in enumerate(weights):
            if mask>>i&1:
                s+=w; k+=1
        if s>=p-1e-12:
            res += (p**k)*((1-p)**(m-k))
    return res

def random_search(p,m,N=10000):
    best=(1,None)
    for _ in range(N):
        x=np.random.exponential(1,size=m); x=x/x.sum()
        val=prob_success(x,p)
        if val<best[0]:
            best=(val,x.copy())
    return best
