from itertools import combinations

def all_downsets(n):
    # recursively generate ideals of Boolean lattice perhaps for n<=5
    sets=list(range(1<<n))
    # downset determined by antichain of maximal elements. brute all families impossible 2^(2^n)
    downs=[]
    for maskfam in range(1<<(1<<n)):
        # n<=4 only
        ok=True
        for A in sets:
            if maskfam>>A &1:
                sub=A
                while True:
                    if not (maskfam>>sub)&1:
                        ok=False; break
                    if sub==0: break
                    sub=(sub-1)&A
                if not ok: break
        if ok: downs.append([A for A in sets if maskfam>>A&1])
    return downs

